async function findBestSqliteAdapter(opts: { sqliteConnector?: SQLiteConnector, resolver?: Resolver }) {
  if (process.versions.bun) {
    return opts.resolver ? opts.resolver.resolve('./runtime/internal/connectors/bun-sqlite') : 'db0/connectors/bun-sqlite'
  }

  // if node:sqlite is available, use it
  if (opts.sqliteConnector === 'native' && isNodeSqliteAvailable()) {
    return opts.resolver ? opts.resolver.resolve('./runtime/internal/connectors/node-sqlite') : 'db0/connectors/node-sqlite'
  }

  if (opts.sqliteConnector === 'sqlite3') {
    return 'db0/connectors/sqlite3'
  }

  if (opts.sqliteConnector === 'better-sqlite3') {
    await ensurePackageInstalled('better-sqlite3')

    return 'db0/connectors/better-sqlite3'
  }

  if (isWebContainer()) {
    await ensurePackageInstalled('sqlite3')

    return 'db0/connectors/sqlite3'
  }

  await ensurePackageInstalled('better-sqlite3')

  return 'db0/connectors/better-sqlite3'
}

export function getGitEnv(): GitInfo {
  // https://github.com/unjs/std-env/issues/59
  const envInfo = {
    // Provider
    provider: process.env.VERCEL_GIT_PROVIDER // vercel
      || (process.env.GITHUB_SERVER_URL ? 'github' : undefined) // github
      || '',
    // Owner
    owner: process.env.VERCEL_GIT_REPO_OWNER // vercel
      || process.env.GITHUB_REPOSITORY_OWNER // github
      || process.env.CI_PROJECT_PATH?.split('/').shift() // gitlab
      || '',
    // Name
    name: process.env.VERCEL_GIT_REPO_SLUG
      || process.env.GITHUB_REPOSITORY?.split('/').pop() // github
      || process.env.CI_PROJECT_PATH?.split('/').splice(1).join('/') // gitlab
      || '',
    // Url
    url: process.env.REPOSITORY_URL || '', // netlify
  }

  if (!envInfo.url && envInfo.provider && envInfo.owner && envInfo.name) {
    envInfo.url = `https://${envInfo.provider}.com/${envInfo.owner}/${envInfo.name}`
  }

  // If only url available (ex: Netlify)
  if (!envInfo.name && !envInfo.owner && envInfo.url) {
    try {
      const { name, owner } = gitUrlParse(envInfo.url)
      envInfo.name = name
      envInfo.owner = owner
    }
    catch {
      // Ignore error
    }
  }

  return {
    name: envInfo.name,
    owner: envInfo.owner,
    url: envInfo.url,
  }
}

async setup(options, nuxt) {
  const clientDir = resolve(packageDir, 'client')
  const workspaceRoot = resolve(packageDir, '../..')
  const PORT = await getPort({ port: 12442 })

  extendViteConfig((config) => {
    config.server ||= {}
    // add proxy to client
    config.server.proxy ||= {}
    // TODO: ws proxy is not working
    config.server.proxy['/__nuxt_devtools__/client'] = {
      target: `http://localhost:${PORT}`,
      changeOrigin: true,
      followRedirects: true,
      ws: true,
    }
    // add fs allow for local modules
    config.server.fs ||= {}
    config.server.fs.allow ||= [
      searchForWorkspaceRoot(process.cwd()),
    ]
    config.server.fs.allow.push(workspaceRoot)
  })

  nuxt.hook('app:resolve', () => {
    startSubprocess(
      {
        command: 'npx',
        args: ['nuxi', 'dev'],
        cwd: clientDir,
        nodeOptions: { stdio: 'pipe' },
        env: {
          NUXT_DEVTOOLS_LOCAL: 'true',
          PORT: PORT.toString(),
        },
      },
      {
        id: 'devtools:local',
        name: 'Nuxt DevTools Local',
        icon: 'logos-nuxt-icon',
      },
      nuxt,
    )
  })

  logger.info(`Nuxt DevTools is using local client from \`${clientDir}\` at port \`${PORT}\``)

  return enableModule(options, nuxt)
}

function toggle(event?: MouseEvent) {
  if (!isAppearanceTransition || !event) {
    isDark.value = !isDark.value
    return
  }

  const x = event.clientX
  const y = event.clientY
  const endRadius = Math.hypot(
    Math.max(x, innerWidth - x),
    Math.max(y, innerHeight - y),
  )
  const transition = document.startViewTransition(async () => {
    isDark.value = !isDark.value
    await nextTick()
  })

  transition.ready.then(() => {
    const clipPath = [
      `circle(0px at ${x}px ${y}px)`,
      `circle(${endRadius}px at ${x}px ${y}px)`,
    ]
    document.documentElement.animate(
      {
        clipPath: isDark.value
          ? clipPath.toReversed()
          : clipPath,
      },
      {
        duration: 400,
        easing: 'ease-in',
        fill: 'forwards',
        pseudoElement: isDark.value
          ? '::view-transition-old(root)'
          : '::view-transition-new(root)',
      },
    )
  })
}

