export function useCommands() {
  const tabs = useEnabledTabs()
  const router = useRouter()

  const fixedCommands: CommandItem[] = [
    {
      id: 'fixed:settings',
      title: 'Settings',
      icon: 'carbon-settings-adjust',
      action: () => {
        router.push('/settings')
      },
    },
    {
      id: 'fixed:docs',
      title: 'Nuxt Documentations',
      icon: 'logos-nuxt-icon',
      action: () => {
        return getNuxtDocsCommands()
      },
    },
  ]

  const tabCommands = computed(() => tabs.value
    .map((i): CommandItem => {
      return {
        id: `tab:${i.name}`,
        title: i.title || i.name,
        icon: i.icon,
        action: () => {
          if ('onClick' in i && i.onClick)
            i.onClick()
          else
            router.push(('path' in i && i.path) ? i.path : `/modules/custom-${i.name}`)
        },
      }
    }))

  return computed(() => {
    return [
      ...fixedCommands,
      ...tabCommands.value,
      ...[...registeredCommands.values()]
        .flatMap(i => toValue(i)),
    ]
  })
}

export async function callOnce (...args: any[]): Promise<void> {
  const autoKey = typeof args[args.length - 1] === 'string' ? args.pop() : undefined
  if (typeof args[0] !== 'string') { args.unshift(autoKey) }
  const [_key, fn, options] = args as [string, (() => any | Promise<any>), CallOnceOptions | undefined]
  if (!_key || typeof _key !== 'string') {
    throw new TypeError('[nuxt] [callOnce] key must be a string: ' + _key)
  }
  if (fn !== undefined && typeof fn !== 'function') {
    throw new Error('[nuxt] [callOnce] fn must be a function: ' + fn)
  }
  const nuxtApp = useNuxtApp()

  if (options?.mode === 'navigation') {
    const removeGuard = useRouter().beforeResolve(() => {
      nuxtApp.payload.once.delete(_key)
      removeGuard()
    })
  }

  // If key already ran
  if (nuxtApp.payload.once.has(_key)) {
    // Allow re-execution during HMR
    if (!import.meta.dev || !_isHmrUpdating) {
      return
    }
  }

  nuxtApp._once ||= {}
  nuxtApp._once[_key] ||= fn() || true
  try {
    await nuxtApp._once[_key]
  } catch (e) {
    delete nuxtApp._once[_key]
    throw e
  }
  nuxtApp.payload.once.add(_key)
  delete nuxtApp._once[_key]
}

export function isVue (id: string, opts: { type?: Array<'template' | 'script' | 'style'> } = {}) {
  const { search } = parseModuleId(id)

  // Bare `.vue` file (in Vite)
  if (id.endsWith('.vue') && !search) {
    return true
  }

  if (!search) {
    return false
  }

  // Component async/lazy wrapper
  if (NUXT_COMPONENT_RE.test(search)) {
    return false
  }

  // Macro
  if (MACRO_RE.test(search) && (search === '?macro=true' || !opts.type || opts.type.includes('script'))) {
    return true
  }

  // Non-Vue or Styles
  if (!VUE_QUERY_RE.test(search)) {
    return false
  }

  if (opts.type) {
    const type = SETUP_QUERY_RE.test(search) ? 'script' : TYPE_QUERY_RE.exec(search)?.[1] as 'script' | 'template' | 'style' | undefined
    if (!type || !opts.type.includes(type)) {
      return false
    }
  }

  // Query `?vue&type=template` (in Webpack or external template)
  return true
}

async (val, get) => {
  if (val && typeof val === 'string') {
    return resolve(await get('rootDir'), val)
  }

  const rootDir = await get('rootDir')

  const srcDir = resolve(rootDir, 'app')
  if (!existsSync(srcDir)) {
    return rootDir
  }

  const srcDirFiles = new Set<string>()
  const files = await readdir(srcDir).catch(() => [])
  for (const file of files) {
    if (file !== 'spa-loading-template.html' && !file.startsWith('router.options')) {
      srcDirFiles.add(file)
    }
  }
  if (srcDirFiles.size === 0) {
    for (const file of ['app.vue', 'App.vue']) {
      if (existsSync(resolve(rootDir, file))) {
        return rootDir
      }
    }
    const keys = ['assets', 'layouts', 'middleware', 'pages', 'plugins'] as const
    const dirs = await Promise.all(keys.map(key => get(`dir.${key}`)))
    for (const dir of dirs) {
      if (existsSync(resolve(rootDir, dir))) {
        return rootDir
      }
    }
  }
  return srcDir
}

export async function createFetchForH3V1() {
  const [{ createApp, toNodeListener }, { fetchNodeRequestHandler }] = await Promise.all([
    import('h3'),
    import('node-mock-http'),
  ])

  const h3App = createApp()
  const nodeHandler = toNodeListener(h3App)

  const registry = new Set<string>()
  const _fetch = fetch

  const h3Fetch = (async (input, _init) => {
    let url: string
    let init = _init
    if (typeof input === 'string') {
      url = input
    }
    else if (input instanceof URL) {
      url = input.toString()
    }
    else {
      url = input.url
      init = {
        method: init?.method ?? input.method,
        body: init?.body ?? input.body,
        headers: init?.headers ?? input.headers,
      }
    }

    const base = url.split('?')[0]!
    if (registry.has(base) || registry.has(url)) {
      url = '/_' + url
    }
    if (url.startsWith('/')) {
      const response = await fetchNodeRequestHandler(nodeHandler, url, init)
      return normalizeFetchResponse(response)
    }
    return _fetch(input, _init)
  }) as typeof fetch

  return {
    h3App: h3App as GenericApp,
    registry,
    fetch: h3Fetch,
  }
}

async function main() {
  const {
    apiPorts,
    watchMode,
  } = await new Promise<ReceiveMessage['start']>((resolve) => {
    listenMessages(({ type, payload }) => {
      if (type === 'start') resolve(payload)
    })
  })

  const port = apiPorts ? await getPort({ ports: apiPorts }) : undefined

  const { startVitest } = await import('vitest/node')

  const customReporter = createCustomReporter((vitest) => {
    listenMessages(async ({ type, payload }) => {
      if (type === 'stop') {
        await vitest.exit(payload.force)
        process.exit()
      }
    })
  })

  const vitest = await startVitest('test', [], watchMode
    ? {
        passWithNoTests: true,
        ui: true,
        watch: true,
        open: false,
        api: { port },
      }
    : { ui: false, watch: false }, {
    test: {
      reporters: ['default', customReporter],
    },
  })

  if (!watchMode) {
    await vitest.exit()
    process.exit()
  }
}

