function wrapTranslationFunctions(ctx: NuxtI18nContext, serverI18n = useRequestEvent()?.context?.nuxtI18n) {
  if (!serverI18n) { return }

  const i18n = ctx.vueI18n.global
  const originalT = i18n.t.bind(i18n)
  type TParams = Parameters<typeof originalT>
  i18n.t = (
    key: string,
    listOrNamed?: string | number | unknown[] | Record<string, unknown>,
    opts?: TranslateOptions<string> | number | string,
  ) => {
    const locale = ((typeof opts === 'object' && opts?.locale) || ctx.getLocale()) as string
    serverI18n?.trackKey(key, locale)
    // @ts-expect-error type mismatch

    return originalT(key, listOrNamed as TParams[1], opts)
  }

  const originalTe = i18n.te.bind(i18n)
  i18n.te = (key, locale) => {
    serverI18n?.trackKey(key, locale || ctx.getLocale())
    return originalTe(key, locale)
  }

  const originalTm = i18n.tm.bind(i18n)
  i18n.tm = (key) => {
    serverI18n?.trackKey(key, ctx.getLocale())
    return originalTm(key)
  }
}

export function cachedFunctionI18n<T, ArgsT extends unknown[] = any[]>(
  fn: (...args: ArgsT) => T | Promise<T>,
  opts: CacheOptions<ArgsT>,
): (...args: ArgsT) => Promise<T | undefined> {
  opts = { maxAge: 1, ...opts }
  const pending: { [key: string]: Promise<T> } = {}

  async function get(key: string, resolver: () => T | Promise<T>) {
    const isPending = pending[key]

    if (!isPending) {
      pending[key] = Promise.resolve(resolver())
    }

    try {
      return await pending[key]
    } finally {
      // Ensure we always clean up, whether the promise resolved or rejected.
      delete pending[key]
    }
  }

  return async (...args) => {
    const key = [opts.name, opts.getKey(...args)].join(':').replace(/:\/$/, ':index')
    const maxAge = opts.maxAge ?? 1
    const isCacheable = !opts.shouldBypassCache(...args) && maxAge >= 0

    const cache = isCacheable && (await storage.getItemRaw<CachedValue<T>>(key))
    if (!cache || cache.ttl < Date.now()) {
      pending[key] = Promise.resolve(fn(...args))
      const value = await get(key, () => fn(...args))

      if (isCacheable) {
        await storage.setItemRaw(key, { ttl: Date.now() + maxAge * 1000, value, mtime: Date.now() })
      }

      return value
    }

    return cache.value
  }
}

export function navigate(nuxtApp: NuxtApp, to: CompatRoute, locale: string) {
  if (!__I18N_ROUTING__ || __DIFFERENT_DOMAINS__) { return }

  const ctx = useNuxtI18nContext(nuxtApp)
  const _ctx = useComposableContext(nuxtApp)

  if (to.path === '/' && ctx.rootRedirect) {
    return navigateTo(localePath(_ctx, ctx.rootRedirect.path, locale), { redirectCode: ctx.rootRedirect.code })
  }

  // skip - pending locale inside navigation middleware
  if (ctx.vueI18n.__pendingLocale && useNuxtApp()._processingMiddleware) {
    return
  }

  // skip - redirection optional prevents prefix removal, reconsider if needed (#2288)
  const detectors = useDetectors(useRequestEvent(), useI18nDetection(nuxtApp), nuxtApp)
  if (detectors.route(to) === locale) {
    return
  }

  // skip redirect if resolved route matches current route (#1889, #2226)
  const destination = switchLocalePath(_ctx, locale, to) || localePath(_ctx, to.fullPath, locale)
  if (isEqual(destination, to.fullPath)) {
    return
  }

  return navigateTo(destination, { redirectCode: ctx.redirectStatusCode })
}

function propsToData(node: MDCElement, documentMeta: MDCData) {
  const { tag = '', props = {} } = node
  return Object.keys(props).reduce(function (data, key) {
    // Ignore internal `__ignoreMap` prop.
    if (key === '__ignoreMap') {
      return data
    }

    const value = props[key]

    // `v-model="foo"`
    if (rxModel.test(key)) {
      return propsToDataRxModel(key, value, data, documentMeta, { native: nativeInputs.includes(tag) })
    }

    // `v-bind="{foo: 'bar'}"`
    if (key === 'v-bind') {
      return propsToDataVBind(key, value, data, documentMeta)
    }

    // `v-on="foo"`
    if (rxOn.test(key)) {
      return propsToDataRxOn(key, value, data, documentMeta)
    }

    // `:foo="bar"`, `v-bind:foo="bar"`
    if (rxBind.test(key)) {
      return propsToDataRxBind(key, value, data, documentMeta)
    }

    const { attribute } = find(html, key)

    // Join string arrays using space, see: https://github.com/nuxt/content/issues/247
    if (Array.isArray(value) && value.every(v => typeof v === 'string')) {
      data[attribute] = value.join(' ')
      return data
    }

    data[attribute] = value

    return data
  }, {} as any)
}

function _defu<T>(baseObject: T, defaults: any, namespace = ".", merger?: Merger): T {
  if (!isPlainObject(defaults)) {
    return _defu(baseObject, {}, namespace, merger);
  }

  const object = { ...defaults };

  for (const key of Object.keys(baseObject as Record<string, any>)) {
    if (key === "__proto__" || key === "constructor") {
      continue;
    }

    const value = (baseObject as Record<string, any>)[key];

    if (value === null || value === undefined) {
      continue;
    }

    if (merger && merger(object, key, value, namespace)) {
      continue;
    }

    if (Array.isArray(value) && Array.isArray(object[key])) {
      object[key] = [...value, ...object[key]];
    } else if (isPlainObject(value) && isPlainObject(object[key])) {
      object[key] = _defu(
        value,
        object[key],
        (namespace ? `${namespace}.` : "") + key.toString(),
        merger,
      );
    } else {
      object[key] = value;
    }
  }

  return object;
}

export async function download(
  url: string,
  filePath: string,
  options: { headers?: Record<string, string | undefined> } = {},
) {
  const infoPath = filePath + ".json";
  const info: { etag?: string } = JSON.parse(await readFile(infoPath, "utf8").catch(() => "{}"));
  const headResponse = await sendFetch(url, {
    method: "HEAD",
    headers: options.headers,
  }).catch(() => undefined);
  const etag = headResponse?.headers.get("etag");
  if (info.etag === etag && existsSync(filePath)) {
    // Already downloaded
    return;
  }
  if (typeof etag === "string") {
    info.etag = etag;
  }

  const response = await sendFetch(url, { headers: options.headers });
  if (response.status >= 400) {
    throw new Error(`Failed to download ${url}: ${response.status} ${response.statusText}`);
  }

  const stream = createWriteStream(filePath);
  await promisify(pipeline)(response.body as any, stream);

  await writeFile(infoPath, JSON.stringify(info), "utf8");
}

async (input, options) => {
  if (input.endsWith(".json")) {
    return (await _httpJSON(input, options)) as TemplateInfo;
  }

  const url = new URL(input);
  let name: string = basename(url.pathname);

  try {
    const head = await sendFetch(url.href, {
      method: "HEAD",
      validateStatus: true,
      headers: {
        authorization: options.auth ? `Bearer ${options.auth}` : undefined,
      },
    });
    const _contentType = head.headers.get("content-type") || "";
    if (_contentType.includes("application/json")) {
      return (await _httpJSON(input, options)) as TemplateInfo;
    }
    const filename = head.headers.get("content-disposition")?.match(/filename="?(.+)"?/)?.[1];
    if (filename) {
      name = filename.split(".")[0]!;
    }
  } catch (error) {
    debug(`Failed to fetch HEAD for ${url.href}:`, error);
  }

  return {
    name: `${name}-${url.href.slice(0, 8)}`,
    version: "",
    subdir: "",
    tar: url.href,
    defaultDir: name,
    headers: {
      Authorization: options.auth ? `Bearer ${options.auth}` : undefined,
    },
  };
}

export async function updateSession<T extends SessionData = SessionData>(
  event: HTTPEvent,
  config: SessionConfig,
  update?: SessionUpdate<T>,
): Promise<Session<T>> {
  const sessionName = config.name || DEFAULT_SESSION_NAME;

  // Access current session
  const context = getEventContext<H3EventContext>(event);
  const session: Session<T> =
    (context.sessions?.[sessionName] as Session<T>) || (await getSession<T>(event, config));

  // Update session data if provided
  if (typeof update === "function") {
    update = update(session.data);
  }
  if (update) {
    Object.assign(session.data, update);
  }

  // Seal and store in cookie
  if (config.cookie !== false && (event as H3Event).res) {
    const sealed = await sealSession(event, config);
    setChunkedCookie(event as H3Event, sessionName, sealed, {
      ...DEFAULT_SESSION_COOKIE,
      expires: config.maxAge ? new Date(session.createdAt + config.maxAge * 1000) : undefined,
      ...config.cookie,
    });
  }

  return session;
}

callHookWith<
    NameT extends HookNameT,
    CallFunction extends (
      hooks: HookCallback[],
      args: Parameters<InferCallback<HooksT, NameT>>,
      name: NameT,
    ) => any,
  >(
    caller: CallFunction,
    name: NameT,
    args: Parameters<InferCallback<HooksT, NameT>>,
  ): ReturnType<CallFunction> {
    const event = this._before || this._after ? { name, args, context: {} } : undefined;
    if (this._before) {
      callEachWith(this._before, event);
    }
    const result = caller(
      this._hooks[name] ? [...this._hooks[name]] : [],
      args as Parameters<InferCallback<HooksT, NameT>>,
      name,
    );
    if ((result as any) instanceof Promise) {
      return result.finally(() => {
        if (this._after && event) {
          callEachWith(this._after, event);
        }
      });
    }
    if (this._after && event) {
      callEachWith(this._after, event);
    }
    return result;
  }

function esmEval(
  ctx: Context,
  code: string,
  filename: string,
  nativeImport: (id: string) => Promise<any>,
  forceTempFile?: boolean,
) {
  const wrapped = `export default ${code}`;
  const uri = forceTempFile
    ? undefined
    : `data:text/javascript;base64,${Buffer.from(wrapped).toString("base64")}`;
  return (...args: any[]) => {
    let tempFile: string | undefined;
    const importViaTempFile = () => {
      tempFile = writeEsmTempFile(wrapped, filename);
      debug(ctx, "[esm]", "[tempfile]", tempFile);
      return nativeImport(pathToFileURL(tempFile));
    };
    const modPromise = uri
      ? nativeImport(uri).catch((error: any) => {
          // Fallback to temp file on ENAMETOOLONG (encrypted home dirs /
          // strict NAME_MAX filesystems).
          if (error?.code !== "ENAMETOOLONG") {
            throw error;
          }
          return importViaTempFile();
        })
      : importViaTempFile();
    return modPromise
      .then((mod) => mod.default(...args))
      .finally(() => {
        if (tempFile) {
          unlink(tempFile).catch(() => {});
        }
      });
  };
}

export default function importMetaResolvePlugin(_ctx: any) {
  return <PluginObj>{
    name: "import-meta-resolve",
    visitor: {
      Program(path) {
        const metas: Array<NodePath<MemberExpression>> = [];

        path.traverse({
          MemberExpression(memberExpPath) {
            const { node } = memberExpPath;

            if (
              node.object.type === "MetaProperty" &&
              node.object.meta.name === "import" &&
              node.object.property.name === "meta" &&
              node.property.type === "Identifier" &&
              node.property.name === "resolve"
            ) {
              metas.push(memberExpPath);
            }
          },
        });

        if (metas.length === 0) {
          return;
        }

        for (const meta of metas) {
          meta.replaceWith({
            type: "ExpressionStatement",
            expression: { type: "Identifier", name: "jitiESMResolve" },
          });
        }
      },
    },
  };
}

export function _genStatement(
  type: ImportExportType,
  specifier: string,
  names?: ESMImport | ESMExport | Array<ESMImport | ESMExport>,
  options: ESMCodeGenOptions = {},
) {
  const specifierString = genString(specifier, options);
  if (!names) {
    return `${type} ${specifierString};`;
  }

  const nameArray = Array.isArray(names);

  const _names = (nameArray ? names : [names]).map((index) => {
    if (typeof index === "string") {
      return { name: index };
    }
    if (index.name === index.as) {
      index = { name: index.name };
    }
    // TODO: Ensure `name` and `as` are valid identifiers
    // TODO: Ensure `as` is provided for default import
    return index;
  });

  const namesString = _names
    .map((index) => (index.as ? `${index.name} as ${index.as}` : index.name))
    .join(", ");
  if (nameArray) {
    return `${type} { ${namesString} } from ${genString(
      specifier,
      options,
    )}${_genImportAttributes(type, options)};`;
  }
  return `${type} ${namesString} from ${genString(
    specifier,
    options,
  )}${_genImportAttributes(type, options)};`;
}

function generateCodeTree(
  files: FileEntry[],
  options: { defaultValue?: string; expandAll?: boolean } = {}
): string {
  const sortedFiles = sortFiles(files);
  const codeBlocks: string[] = [];

  for (const file of sortedFiles) {
    const lang = file.language;
    const filename = file.relativePath;

    // Use 4 backticks for markdown files to avoid conflicts
    const fence = lang === "md" ? "````" : "```";
    codeBlocks.push(`${fence}${lang} [${filename}]`);
    codeBlocks.push(file.content);
    codeBlocks.push(fence);
    codeBlocks.push("");
  }

  const attrs: string[] = [];
  if (options.defaultValue) {
    attrs.push(`defaultValue="${options.defaultValue}"`);
  }
  if (options.expandAll) {
    attrs.push(`expandAll`);
  }
  const propsStr = attrs.length > 0 ? `{${attrs.join(" ")}}` : "";
  const contents = `::code-tree${propsStr}\n\n${codeBlocks.join("\n").trim()}\n\n::`;

  return contents;
}

async function handler(request: Request): Promise<Response> {
  const app = createSSRApp(RouterView);
  const router = createRouter({ history: createMemoryHistory(), routes });
  app.use(router);

  const url = new URL(request.url);
  const href = url.href.slice(url.origin.length);

  await router.push(href);
  await router.isReady();

  const assets = clientAssets.merge(
    ...(await Promise.all(
      router.currentRoute.value.matched
        .map((to) => to.meta.assets)
        .filter(Boolean)
        .map((fn) => (fn as any)().then((m: any) => m.default))
    ))
  );

  const head = createHead();

  head.push({
    link: [
      ...assets.css.map((attrs: any) => ({ rel: "stylesheet", ...attrs })),
      ...assets.js.map((attrs: any) => ({ rel: "modulepreload", ...attrs })),
    ],
    script: [{ type: "module", src: clientAssets.entry }],
  });

  const renderedApp = await renderToString(app);

  const html = await transformHtmlTemplate(head, htmlTemplate(renderedApp));

  return new Response(html, {
    headers: { "Content-Type": "text/html;charset=utf-8" },
  });
}
